function render_invoice_row( $invoice, $user ) {
    if ( $user['role'] !== 'admin' && $user['id'] !== $invoice['owner_id'] ) { return ''; }
    $out = '';
    foreach ( $invoice['lines'] as $line ) { $out .= '<td>' . esc_html( $line['label'] ) . '</td>'; }
    return $out;
}

function render_report_row( $report, $user ) {
    if ( $user['role'] !== 'admin' && $user['id'] !== $report['owner_id'] ) { return ''; }
    $out = '';
    foreach ( $report['columns'] as $col ) { $out .= '<td>' . esc_html( $col['title'] ) . '</td>'; }
    return $out;
}
